"use client";

import { useEffect, useMemo, useState } from "react";
import Plantilla1Static from "./plantillas/Plantilla1Static";
import Plantilla2Static from "./plantillas/Plantilla2Static";
import Plantilla3Static from "./plantillas/Plantilla3Static";
import Plantilla4Static from "./plantillas/Plantilla4Static";

export default function PagoFastCashStatic({
  token,
  tipoPlantilla,
}: {
  token: string;
  tipoPlantilla?: string | number;
}) {
  const [data, setData] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const origin = useMemo(() => {
    if (typeof window === "undefined") return "";
    return window.location.origin;
  }, []);

  async function copyToClipboard(text: string) {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 1200);
    } catch {
      setError("No se pudo copiar");
    }
  }

  useEffect(() => {
    if (!token) {
      setError("Token no recibido");
      return;
    }

    let cancel = false;

    (async () => {
      try {
        setError(null);

        const res = await fetch(`/api/plantillas-temporales-3/${token}`, {
          cache: "no-store",
        });

        const json = await res.json().catch(() => null);
        const payload = json?.data ?? json;

        if (!cancel) {
          setData(payload);
        }
      } catch {
        if (!cancel) {
          setError("Error cargando datos");
        }
      }
    })();

    return () => {
      cancel = true;
    };
  }, [token]);

  if (error) return <div className="text-white">{error}</div>;
  if (!data) return <div className="text-white">Cargando...</div>;

  const props = {
    data,
    origin,
    copied,
    onCopy: copyToClipboard,
  };

  // 🔥 AQUÍ ESTÁ EL FIX REAL
  const plantillaFinal = String(
    tipoPlantilla ?? data?.tipo_plantilla ?? "1"
  ).trim();

  console.log("tipoPlantilla prop:", tipoPlantilla);
  console.log("data.tipo_plantilla:", data?.tipo_plantilla);
  console.log("plantillaFinal:", plantillaFinal);

  switch (plantillaFinal) {
    case "2":
      return <Plantilla2Static {...props} />;
    case "3":
      return <Plantilla3Static {...props} />;
    case "4":
      return <Plantilla4Static {...props} />;
    case "1":
    default:
      return <Plantilla1Static {...props} />;
  }
}